from models.cricket_domain import CricketMatch, CricketTeam, Innings
from tools.cricket_mechanics import CricketMechanicsEngine
from datetime import datetime
import json

class OrchestratorAgent:
    """
    Master agent that coordinates entire cricket match.
    Responsibilities: toss logic, team selection, phase transitions, result determination.
    """

    def __init__(self, match: CricketMatch, llm_client):
        self.match = match
        self.llm_client = llm_client
        self.agent_id = "orchestrator-main"
        self.reasoning_log = []
        self.tools = {
            "apply_powerplay_rules": CricketMechanicsEngine.apply_powerplay_rules,
            "validate_match_state": CricketMechanicsEngine.validate_match_state,
            "determine_match_winner": CricketMechanicsEngine.determine_match_winner,
        }

    async def execute_toss_logic(self) -> str:
        """
        Reason about toss: which team won, what should they choose (bat/bowl)?
        This demonstrates agent reasoning without simulation yet.
        """
        prompt = f"""
        Simulate a cricket toss between {self.match.team1.team_name} (#{self.match.team1.odi_ranking}) 
        and {self.match.team2.team_name} (#{self.match.team2.odi_ranking}).
        Venue: {self.match.venue}

        Facts:
        - {self.match.team1.team_name} home ground: {self.match.team1.home_ground}
        - {self.match.team2.team_name} home ground: {self.match.team2.home_ground}
        - {self.match.team1.team_name} ODI ranking: {self.match.team1.odi_ranking}
        - {self.match.team2.team_name} ODI ranking: {self.match.team2.odi_ranking}

        Decide:
        1. Which team wins the toss (reason about form, recent results, captain experience)?
        2. Should the toss-winning captain choose to bat or bowl first (consider ground, weather patterns)?

        Respond with JSON: {{"toss_winner": "team_name", "choice": "bat|bowl", "reasoning": "explanation"}}
        """
        # In production, call self.llm_client with prompt
        # For now, return simulated decision
        return json.dumps({
            "toss_winner": self.match.team1.team_name,
            "choice": "bat",
            "reasoning": f"{self.match.team1.team_name} won toss, chose to bat first. Higher-ranked team prefers batting in favorable conditions."
        })

    def transition_phase(self, new_phase: str) -> None:
        """Safely transition match to next phase (pre_match -> innings1 -> innings2 -> completed)."""
        valid_transitions = {
            "pre_match": ["innings1"],
            "innings1": ["innings2"],
            "innings2": ["completed"],
        }
        if new_phase not in valid_transitions.get(self.match.match_phase, []):
            raise ValueError(f"Invalid phase transition: {self.match.match_phase} -> {new_phase}")
        self.match.match_phase = new_phase
        self.reasoning_log.append({
            "timestamp": datetime.utcnow().isoformat(),
            "action": "phase_transition",
            "from": self.match.match_phase,
            "to": new_phase,
        })

class CricketAgent:
    """Advanced agent with multi-layer memory and execution tracking."""

    def __init__(self, player_name: str):
        self.player_name = player_name
        # Working memory: current match state
        self.working_memory = {
            'current_over': None,
            'batsman_stance': None,
            'field_config': None
        }
        # Episodic memory: historical interactions
        self.episodic_memory = []
        # Semantic memory: learned policies
        self.semantic_policies = {
            'powerplay_aggression': 0.85,
            'death_bowling_lines': ['yorker', 'slower_ball'],
            'bumrah_effectiveness_vs_lefty': 0.78
        }

    def perceive(self, match_state: dict) -> dict:
        """Encode environmental observation."""
        self.working_memory.update(match_state)
        return {
            'batsman': match_state.get('batsman_name'),
            'runs_needed': match_state.get('runs_needed'),
            'balls_left': match_state.get('balls_left')
        }

    def decide(self, perception: dict) -> str:
        """Multi-layer decision synthesis."""
        # Layer 1: Semantic rules (general knowledge)
        if perception['balls_left'] <= 6:
            base_strategy = 'death_bowling'
        else:
            base_strategy = 'regular_attack'

        # Layer 2: Episodic lookup (past outcomes)
        similar_episodes = [
            ep for ep in self.episodic_memory 
            if ep['batsman'] == perception['batsman']
        ]
        if similar_episodes:
            past_effective_action = similar_episodes[-1]['effective_action']
        else:
            past_effective_action = None

        # Layer 3: Working memory integration (current context)
        decision = past_effective_action or base_strategy

        return decision

    def execute_and_log(self, decision: str, outcome: float) -> None:
        """Execute action and persist to episodic memory."""
        episode = {
            'timestamp': len(self.episodic_memory),
            'decision': decision,
            'outcome_reward': outcome,
            'batsman': self.working_memory['batsman_stance'],
            'effective_action': decision if outcome > 0.5 else None
        }
        self.episodic_memory.append(episode)

        # Update semantic policy if strong signal
        if outcome > 0.8:
            self.semantic_policies[f'{decision}_strength'] = \
                self.semantic_policies.get(f'{decision}_strength', 0.5) + 0.1

# Usage
agent = CricketAgent('Rohit')
match = {
    'batsman_name': 'Virat Kohli',
    'runs_needed': 15,
    'balls_left': 4
}

perception = agent.perceive(match)
decision = agent.decide(perception)
agent.execute_and_log(decision, outcome=0.92)  # Bumrah bowled a yorker, got a wicket

# ANTI-PATTERN: Single-pass decision, no memory
class BadCricketAgent:
    def make_field_decision(self, current_batsman: str, ball_count: int) -> str:
        # Only looks at current state, ignores history
        if ball_count > 15:
            return 'aggressive_field'
        return 'defensive_field'  # Pure reactivity, learns nothing

# BEST PRACTICE: Hybrid reactive-deliberative with memory
class GoodCricketAgent:
    def __init__(self):
        self.decision_cache = {}  # Episodic memory
        self.policy_weights = {'aggressive': 0.6, 'defensive': 0.4}

    def make_field_decision(self, batsman: str, ball_count: int, match_phase: str) -> str:
        # Reactive path for known patterns (low latency)
        cache_key = f"{batsman}_{match_phase}"
        if cache_key in self.decision_cache:
            return self.decision_cache[cache_key]  # O(1) lookup

        # Deliberative path for novel situations (high quality)
        deliberate_decision = self._compute_optimal_field(
            batsman=batsman,
            ball_count=ball_count,
            phase=match_phase
        )

        # Store for next time (learning)
        self.decision_cache[cache_key] = deliberate_decision
        return deliberate_decision

    def _compute_optimal_field(self, batsman: str, ball_count: int, phase: str) -> str:
        # Multi-factor deliberation
        if phase == 'powerplay':
            return 'aggressive_field'
        elif batsman in ['Kohli', 'Sharma']:
            return 'balanced_field'  # Best batsmen get balanced pressure
        else:
            return 'defensive_field'

    def update_policy(self, batsman: str, decision: str, outcome_reward: float) -> None:
        """Asynchronous policy refinement from episode outcome."""
        decision_key = f"{batsman}_{decision}"
        self.policy_weights[decision_key] = \
            self.policy_weights.get(decision_key, 0.5) * 0.9 + outcome_reward * 0.1

# Usage comparison
bad_agent = BadCricketAgent()
good_agent = GoodCricketAgent()

# Bad agent: repeated computation, no learning
for _ in range(100):
    bad_agent.make_field_decision('Kohli', 12)  # Recomputes each time

# Good agent: first call deliberates, subsequent calls are instant
good_agent.make_field_decision('Kohli', 12, 'middle_overs')  # Deliberates
good_agent.make_field_decision('Kohli', 12, 'middle_overs')  # Cached response (fast)
good_agent.update_policy('Kohli', 'balanced_field', outcome_reward=0.95)  # Learns
